import { forwardRef, useState } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { User } from "lucide-react";
import type { ComponentPropsWithoutRef, ReactNode } from "react";
import { cn } from "@/lib/utils";

const avatarFaceVariants = cva(
  "inline-flex shrink-0 items-center justify-center overflow-hidden bg-(--avatar-bg) font-medium text-(--avatar-fg)",
  {
    variants: {
      size: {
        xs: "size-(--avatar-xs-size) [font-size:var(--avatar-xs-font-size)]",
        sm: "size-(--avatar-sm-size) [font-size:var(--avatar-sm-font-size)]",
        md: "size-(--avatar-md-size) [font-size:var(--avatar-md-font-size)]",
        lg: "size-(--avatar-lg-size) [font-size:var(--avatar-lg-font-size)]",
        xl: "size-(--avatar-xl-size) [font-size:var(--avatar-xl-font-size)]",
        "2xl": "size-(--avatar-2xl-size) [font-size:var(--avatar-2xl-font-size)]",
        "3xl": "size-(--avatar-3xl-size) [font-size:var(--avatar-3xl-font-size)]",
      },
      shape: {
        squircle: "",
        circle: "rounded-full",
      },
    },
    compoundVariants: [
      { shape: "squircle", size: "xs", class: "rounded-(--avatar-xs-radius)" },
      { shape: "squircle", size: "sm", class: "rounded-(--avatar-sm-radius)" },
      { shape: "squircle", size: "md", class: "rounded-(--avatar-md-radius)" },
      { shape: "squircle", size: "lg", class: "rounded-(--avatar-lg-radius)" },
      { shape: "squircle", size: "xl", class: "rounded-(--avatar-xl-radius)" },
      { shape: "squircle", size: "2xl", class: "rounded-(--avatar-2xl-radius)" },
      { shape: "squircle", size: "3xl", class: "rounded-(--avatar-3xl-radius)" },
    ],
    defaultVariants: {
      size: "md",
      shape: "squircle",
    },
  },
);

const fallbackIconSizeClasses = {
  xs: "[width:var(--avatar-xs-icon-size)] [height:var(--avatar-xs-icon-size)]",
  sm: "[width:var(--avatar-sm-icon-size)] [height:var(--avatar-sm-icon-size)]",
  md: "[width:var(--avatar-md-icon-size)] [height:var(--avatar-md-icon-size)]",
  lg: "[width:var(--avatar-lg-icon-size)] [height:var(--avatar-lg-icon-size)]",
  xl: "[width:var(--avatar-xl-icon-size)] [height:var(--avatar-xl-icon-size)]",
  "2xl": "[width:var(--avatar-2xl-icon-size)] [height:var(--avatar-2xl-icon-size)]",
  "3xl": "[width:var(--avatar-3xl-icon-size)] [height:var(--avatar-3xl-icon-size)]",
} as const;

type AvatarSize = NonNullable<VariantProps<typeof avatarFaceVariants>["size"]>;
type AvatarShape = NonNullable<VariantProps<typeof avatarFaceVariants>["shape"]>;

export type AvatarProps = Omit<ComponentPropsWithoutRef<"span">, "children"> & {
  src?: string;
  alt?: string;
  fallback?: string;
  size?: AvatarSize;
  shape?: AvatarShape;
  /** Icon rendered inside the avatar status badge shell. */
  status?: ReactNode;
  /** Optional classes applied to the status badge shell (e.g. tinted backgrounds). */
  statusClassName?: string;
};

export const Avatar = forwardRef<HTMLSpanElement, AvatarProps>(
  (
    {
      className,
      src = "",
      alt = "",
      fallback = "",
      size = "md",
      shape = "squircle",
      status,
      statusClassName,
      ...props
    },
    ref,
  ) => {
    const [imageError, setImageError] = useState(false);
    const showImage = Boolean(src) && !imageError;
    const initials = fallback.trim().slice(0, 2).toUpperCase();
    const label = alt || initials || "User avatar";

    return (
      <span
        ref={ref}
        role="img"
        aria-label={label}
        data-size={size}
        data-shape={shape}
        className={cn("relative inline-flex shrink-0 select-none", className)}
        {...props}
      >
        <span className={avatarFaceVariants({ size, shape })}>
          {showImage ? (
            <img
              src={src}
              alt=""
              className="size-full object-cover"
              onError={() => {
                setImageError(true);
              }}
            />
          ) : initials ? (
            <span aria-hidden="true">{initials}</span>
          ) : (
            <User className={cn(fallbackIconSizeClasses[size], "text-(--color-muted-foreground)")} aria-hidden="true" />
          )}
        </span>
        {status ? (
          <span
            aria-hidden="true"
            className={cn(
              "absolute bottom-0 right-0 flex size-(--avatar-status-size) translate-x-1/4 translate-y-1/4 items-center justify-center rounded-full bg-(--avatar-status-bg) [box-shadow:0_0_0_var(--avatar-status-ring-width)_var(--avatar-status-ring)] [&_svg]:size-(--avatar-status-icon-size)",
              statusClassName,
            )}
          >
            {status}
          </span>
        ) : null}
      </span>
    );
  },
);

Avatar.displayName = "Avatar";

/* Avatar component tokens — override these to customise avatars. */
:root {
  /* Per-size dimensions */
  --avatar-xs-size: 16px;
  --avatar-sm-size: 20px;
  --avatar-md-size: 24px;
  --avatar-lg-size: 28px;
  --avatar-xl-size: 32px;
  --avatar-2xl-size: 40px;
  --avatar-3xl-size: 46px;

  /* Per-size squircle radii */
  --avatar-xs-radius: 4px;
  --avatar-sm-radius: 5px;
  --avatar-md-radius: 5px;
  --avatar-lg-radius: 6px;
  --avatar-xl-radius: 6px;
  --avatar-2xl-radius: 8px;
  --avatar-3xl-radius: 8px;

  /* Per-size initials font sizes */
  --avatar-xs-font-size: 11px;
  --avatar-sm-font-size: 13px;
  --avatar-md-font-size: 14px;
  --avatar-lg-font-size: 14px;
  --avatar-xl-font-size: 16px;
  --avatar-2xl-font-size: 18px;
  --avatar-3xl-font-size: 20px;

  /* Per-size fallback icon sizes */
  --avatar-xs-icon-size: 10px;
  --avatar-sm-icon-size: 12px;
  --avatar-md-icon-size: 14px;
  --avatar-lg-icon-size: 16px;
  --avatar-xl-icon-size: 18px;
  --avatar-2xl-icon-size: 22px;
  --avatar-3xl-icon-size: 24px;

  /* Surfaces */
  --avatar-bg: var(--color-muted);
  --avatar-fg: var(--color-muted-foreground);

  /* Status badge shell — slot/prop content is the icon only */
  --avatar-status-size: 10px;
  --avatar-status-icon-size: 6px;
  --avatar-status-bg: var(--color-background);
  --avatar-status-ring: var(--color-background);
  --avatar-status-ring-width: 2px;
}
